insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:4-5-business-location:misc:fcabf834', 'business', 'business:4-5-business-location', '4.5 Business Location', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students write that ''an online business doesn''t need to think about location at all.''</p><p><strong>✅ The correct idea:</strong> Online businesses still have critical location decisions — particularly for their warehouses. They need good transport links (road/rail), a reliable labour supply, and affordable land. The Wool Warehouse is a clear example of deliberate location planning for an online business.</p>", "question": "What location factor is MOST important for an online retailer choosing where to put its warehouse?", "options": ["Proximity to customers — the warehouse should sit near shoppers directly", "Proximity to competitors — the warehouse should sit near rival firms", "Good transport links — road and rail access for fast nationwide delivery", "City centre visibility — the warehouse should boost brand recognition locally"]}'::jsonb, '{"answer": 2, "explain": "Online retailers don''t need to be near customers physically — they reach them through delivery. What matters most for a warehouse is excellent road and rail links to get parcels to customers quickly and cheaply across the country."}'::jsonb),
('business:4-5-business-location:misc:8e3eeb1a', 'business', 'business:4-5-business-location', '4.5 Business Location', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students write that ''government grants automatically make a location the best choice.''</p><p><strong>✅ The correct idea:</strong> Government incentives reduce costs but do not eliminate other disadvantages. A location with good grants but poor transport links, scarce skilled labour, or no market access may still be unsuitable for certain businesses.</p>", "question": "A business receives a £100,000 enterprise zone grant to locate in a remote area with no motorway access and few local workers. Should it definitely accept?", "options": ["Yes — a grant of that size always makes any site worthwhile", "Not necessarily — poor transport and labour could outweigh the grant", "Yes — government grants always cancel out every location downside", "No — businesses should always reject grants tied to remote areas"]}'::jsonb, '{"answer": 1, "explain": "Government incentives reduce costs but cannot fix fundamental disadvantages like poor transport infrastructure or scarce skilled workers. The overall location package must be evaluated — grants are just one factor among many."}'::jsonb),
('business:4-5-business-location:misc:1399002d', 'business', 'business:4-5-business-location', '4.5 Business Location', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students believe all businesses must locate near their raw materials.</p><p><strong>✅ The correct idea:</strong> Proximity to raw materials only matters when materials are bulky, perishable, or expensive to transport. A business making small, lightweight products (e.g., greeting cards) has no reason to locate near raw materials.</p>", "question": "Which of the following businesses has the STRONGEST reason to locate near its raw materials?", "options": ["A greeting card manufacturer using lightweight card and paper", "A software development company selling downloadable digital products", "A cheese producer using fresh, perishable local milk", "An online clothing retailer shipping garments nationwide"]}'::jsonb, '{"answer": 2, "explain": "Fresh milk is perishable and bulky — it cannot travel long distances before spoiling. A cheese producer must be near its milk supply. The other businesses use materials that are either lightweight, digital, or easily shipped over long distances."}'::jsonb),
('business:4-5-business-location:misc:6a9cf96c', 'business', 'business:4-5-business-location', '4.5 Business Location', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For a 7-mark ''discuss'' or ''evaluate'' question, students list location factors without making a final judgement.</p><p><strong>✅ The correct idea:</strong> The examiner''s report highlights that most students gain marks for application and analysis but miss evaluation marks by not making a judgement. You MUST weigh up which factor is most important and state WHY, using context from the case study. Even a simple, contextualised judgement earns evaluation marks.</p>", "question": "Most students score around 4/7 on a location evaluate question. What do they typically miss?", "options": ["They don''t name any relevant location factors at all", "They don''t apply their answer to the specific business", "They don''t make a final judgement on the most important factor", "They write far too much without ever reaching a conclusion"]}'::jsonb, '{"answer": 2, "explain": "The examiner''s report consistently flags this — most candidates demonstrate application and analysis but skip the evaluation mark by failing to make a final contextualised judgement. Even a short, specific conclusion earns evaluation marks."}'::jsonb),
('business:4-5-business-location:misc:7009ae80', 'business', 'business:4-5-business-location', '4.5 Business Location', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think ''Silicon Fen'' is in Silicon Valley, USA.</p><p><strong>✅ The correct idea:</strong> Silicon Fen is an area near Cambridge, UK. It is named after the Fens (the flat marshy land near Cambridge). It is a cluster of ICT firms and highly skilled technology workers, not connected to Silicon Valley in California.</p>", "question": "Where is ''Silicon Fen'' and why is it relevant to business location?", "options": ["San Francisco, USA — it is the home of tech giants like Apple and Google", "Near Cambridge, UK — it is a cluster of ICT firms and skilled tech workers", "In the north of England — it was created by the Northern Powerhouse initiative", "In South Wales — it is one of four enterprise zones in the region"]}'::jsonb, '{"answer": 1, "explain": "Silicon Fen is near Cambridge, UK — named after the flat Fens landscape. It is a cluster of ICT businesses that attracts and benefits from the pool of highly skilled technology graduates from Cambridge University."}'::jsonb),
('business:4-5-business-location:misc:8714cbc4', 'business', 'business:4-5-business-location', '4.5 Business Location', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> When asked to ''analyse one factor'', students write about several factors briefly rather than one factor in depth.</p><p><strong>✅ The correct idea:</strong> The examiner wants ONE factor developed with three steps: Understanding (explain the factor) → Application (link to the specific business using case study evidence) → Analysis (explain the impact on the business). Two brief points will not score full marks.</p>", "question": "On a 3-mark ''Analyse one location factor'' question, a student writes two sentences about two different factors. How many marks do they score?", "options": ["3 marks — covering two different factors shows good breadth of knowledge", "2 marks — one mark is awarded for each factor mentioned", "1 mark — without U, APP and AN for one factor, marks are capped", "0 marks — only one location factor should ever be discussed"]}'::jsonb, '{"answer": 2, "explain": "The 3-mark U → APP → AN chain requires depth on ONE factor, not breadth across several. Two brief mentions of different factors can only earn at most 1 mark — without Application and Analysis, the chain is incomplete."}'::jsonb),
('business:4-5-business-location:tips:6bdca529', 'business', 'business:4-5-business-location', '4.5 Business Location', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1 mark — One Specific Point. Full Stop. Move On.", "reading": "\n      <p>A 1-mark <strong>''Identify'' or ''State''</strong> question needs exactly one correct, specific point. No explanation, no examples, no paragraphs required.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>One clear, specific location factor = ✅ 1 mark</li>\n        <li>A vague or repeated answer = ❌ 0 marks</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"The location.\"</em><br/>\n      Too vague — this just repeats the topic of the question.</p>\n      <p><strong>✅ Good Answers (1 mark each):</strong></p>\n      <ul>\n        <li><em>\"Proximity to customers / the market.\"</em></li>\n        <li><em>\"Cost of the site / rent.\"</em></li>\n        <li><em>\"Transport infrastructure / road links.\"</em></li>\n        <li><em>\"Government incentives / enterprise zone.\"</em></li>\n        <li><em>\"Proximity to a supply of labour / workers.\"</em></li>\n      </ul>\n      <p><strong>⏱️ Exam Tip:</strong> Do NOT write more than one sentence for a 1-mark question. Move on quickly — every minute counts in the exam.</p>\n    ", "question": "Which of these answers would score 1 mark for ''Identify one factor a business considers when choosing its location''?", "options": ["\"Location is very important for all businesses.\"", "\"Proximity to the market / nearness to customers.\"", "\"Businesses need to think carefully about where they are.\"", "\"The area.\""]}'::jsonb, '{"answer": 1, "explain": "Only a specific, named factor scores the mark — ''proximity to the market'' is precise and correct. The other options are all vague restatements of the question and would score zero."}'::jsonb),
('business:4-5-business-location:tips:d7d5c15d', 'business', 'business:4-5-business-location', '4.5 Business Location', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "\n      <p>A 3-mark <strong>''Analyse''</strong> question awards one mark for each of three steps. Miss any one and you lose that mark — even if the rest is excellent.</p>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State and briefly explain the location factor you are discussing.</li>\n        <li><strong>Step 2 — Application (APP):</strong> Link it directly to the specific business using evidence from the case study. Quote or paraphrase specific details.</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> Explain the financial or operational impact on the business. Keep asking \"So what?\" until you reach a bottom-line effect (costs, revenue, profit, productivity).</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark — only U):</strong><br/>\n      <em>\"AM plc should locate where there are skilled workers because they are important for production.\"</em><br/>\n      Vague, no case study link, no analysis of impact on the business.</p>\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"AM plc must locate in an area with a supply of skilled engineers (U), as its Warwickshire site already employs over 3,000 highly skilled workers who use up-to-date machinery to produce each luxury car by hand (APP). If AM plc struggled to recruit these workers, productivity would fall and quality could deteriorate, threatening the premium reputation and pricing of its luxury cars (AN).\"</em></p>\n      <p><strong>🚫 Knowledge Dumping Warning:</strong> Do NOT write everything you know about business location. Pick ONE factor and develop it fully through all three steps. Two half-finished points will not earn full marks.</p>\n      <p><strong>Sentence starters:</strong></p>\n      <ul>\n        <li><em>U: \"One factor [business name] would consider is...\"</em></li>\n        <li><em>APP: \"This is evident because the text states that...\" / \"In the case of [business]...\"</em></li>\n        <li><em>AN: \"As a result, the business would...\" / \"This means costs would...\" / \"This could lead to...\"</em></li>\n      </ul>\n    ", "question": "A student analyses AM plc''s location by writing: ''AM plc should locate where there are skilled workers because they are important.'' How many marks does this score?", "options": ["3 marks — it names skilled workers and links this clearly to AM plc", "2 marks — it shows knowledge and some application to AM plc''s case", "1 mark — it states the factor but gives no application or analysis", "0 marks — skilled workers is not considered a genuine location factor"]}'::jsonb, '{"answer": 2, "explain": "This scores only 1 mark (U) — it names the factor but fails to apply it using specific evidence from the AM plc case study (APP) and gives no analysis of the financial or operational consequence (AN). The chain is U → APP → AN and all three steps are needed."}'::jsonb),
('business:4-5-business-location:tips:b41df59a', 'business', 'business:4-5-business-location', '4.5 Business Location', 'tips', 'mcq', 1, '{"readingTitle": "Recommend — 3 marks — Make a Decision, Then Back It Up with Both Sides", "reading": "\n      <p>A 3-mark <strong>''Recommend''</strong> question has a specific structure. There is 1 mark for a clear judgement and 2 marks for justification. Crucially, your justification must address BOTH sides.</p>\n      <p><strong>The Structure:</strong></p>\n      <ul>\n        <li><strong>Judgement (1 mark):</strong> State your clear recommendation — e.g., \"Lo-Cost should / should not locate at Heathrow Airport.\"</li>\n        <li><strong>Justification (2 marks):</strong> Explain precisely WHY using specific details from the case study. Your justification must cover both the advantages AND the drawbacks — one-sided answers earn at most 1 justification mark.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n      <em>\"Lo-Cost should not locate at Heathrow because it is expensive.\"</em><br/>\n      Only earns the judgement mark — ''expensive'' is too vague, and there is no case study reference.</p>\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"Lo-Cost Rental should NOT locate at Heathrow Airport (JUDGEMENT). The very high cost of renting a service desk and parking spaces at the airport would make it almost impossible for Lo-Cost to maintain its low-priced model while staying profitable. Furthermore, well-established competitors such as Hertz and Avis can subsidise lower prices with revenue from premium cars — a strategy Lo-Cost cannot replicate (JUSTIFICATION ×2).\"</em></p>\n      <p><strong>💡 The Rule:</strong> Justification MUST address both sides to earn 2 justification marks. Defending only one side = maximum 1 justification mark.</p>\n    ", "question": "Why does ''Lo-Cost should not locate at Heathrow because it is expensive'' only score 1 out of 3 marks?", "options": ["It scores 0 — cost is never accepted as a valid location factor", "It scores 1 — just the judgement mark; ''expensive'' is too vague", "It scores 2 — the judgement mark plus one justification point", "It scores 3 — a clear decision alone is enough for full marks"]}'::jsonb, '{"answer": 1, "explain": "This earns only the judgement mark (1/3). To score the two justification marks, you need specific case study detail AND consideration of both sides — why Heathrow is unsuitable for Lo-Cost AND why competitors like Hertz can sustain the cost when Lo-Cost cannot."}'::jsonb),
('business:4-5-business-location:tips:07b943a0', 'business', 'business:4-5-business-location', '4.5 Business Location', 'tips', 'mcq', 1, '{"readingTitle": "Discuss / Evaluate — 7 marks — 4 Paragraphs — Don''t Forget to Judge!", "reading": "\n      <p>A 7-mark <strong>''Discuss''</strong> or <strong>''Evaluate''</strong> question uses levels of response marking. To reach the top level (5–7 marks), you must demonstrate <strong>application</strong>, <strong>analysis</strong>, AND <strong>evaluation</strong>.</p>\n      <p><strong>⚠️ The examiner''s report warns:</strong> Most candidates gain around 4/7 by demonstrating application and analysis well — but only the very best pick up evaluation marks. Even a simple judgement is worth marks. Don''t skip it!</p>\n      <p><strong>The 4-Paragraph Structure:</strong></p>\n      <ul>\n        <li><strong>Para 1 — K &amp; U:</strong> Introduce your first location factor with knowledge and understanding. Explain what it means and why it matters.</li>\n        <li><strong>Para 2 — APP &amp; AN:</strong> Apply your first factor to the specific business using evidence from the case study. Analyse the impact on the business.</li>\n        <li><strong>Para 3 — APP &amp; AN:</strong> Introduce a second factor or the opposing perspective. Apply it to the business and analyse the impact.</li>\n        <li><strong>Para 4 — EVAL (3 points = Decision + Context + Impact/Reasoning):</strong> Make a clear judgement about which factor is most important, using specific context from the business to justify your conclusion.</li>\n      </ul>\n      <p><strong>Evaluation sentence starters:</strong></p>\n      <ul>\n        <li><em>\"Overall, I believe the most important factor for [business] was... because...\"</em></li>\n        <li><em>\"However, this depends on whether...\"</em></li>\n        <li><em>\"The decision to [go online / locate here] was [justified / unjustified] because, given that [specific context]...\"</em></li>\n      </ul>\n      <p><strong>🚫 The Most Common Mistake:</strong> Writing a conclusion that simply repeats the two points already made. That earns 0 evaluation marks. A real evaluation makes a <em>judgement about which factor matters most</em> and explains <em>why</em>, using the specific business context.</p>\n      <p><strong>✅ Simple but effective evaluation example (Costa Coffee):</strong><br/>\n      <em>\"Overall, the most important factor for Costa Coffee was the high footfall from the town centre location, because as a retailer selling products in person — not online — passing trade is essential for survival. Without customers walking past, no other factor matters.\"</em><br/>\n      This earns all 3 evaluation marks: a specific judgement (footfall), justified in context (Costa sells in person), with clear reasoning (passing trade is essential).</p>\n    ", "question": "The Costa Coffee evaluation example earns 3 evaluation marks. What three things does it include?", "options": ["Three separate advantages of choosing a busy town centre spot", "A clear judgement, specific context about Costa, and its reasoning", "A definition of footfall, one advantage, and one clear disadvantage", "Two full analysis paragraphs and a short summary of key points"]}'::jsonb, '{"answer": 1, "explain": "A full 3-mark evaluation needs: (1) a clear decision about which factor is most important, (2) specific context from the business (Costa sells face-to-face, not online), and (3) reasoning explaining why that factor matters most — not simply repeating earlier analysis."}'::jsonb),
