('business:4-5-business-location:match:611b8683', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Location”?", "options": ["Nearness to something — such as a market, raw materials, or a labour supply.", "The roads, railways, airports and ports in an area for transporting goods and people, including ICT infrastructure like broadband.", "The place where a business is sited.", "A government-designated area offering incentives including reduced business rates, lower taxes on investment, and superfast broadband to attract businesses."]}'::jsonb, '{"answer": 2, "explain": "“Location” means: The place where a business is sited."}'::jsonb),
('business:4-5-business-location:match:53e784c4', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Proximity”?", "options": ["The roads, railways, airports and ports in an area for transporting goods and people, including ICT infrastructure like broadband.", "A government-designated area offering incentives including reduced business rates, lower taxes on investment, and superfast broadband to attract businesses.", "Nearness to something — such as a market, raw materials, or a labour supply.", "An area where businesses can import goods without paying tariffs or VAT, unless those goods are sold in the wider UK market."]}'::jsonb, '{"answer": 2, "explain": "“Proximity” means: Nearness to something — such as a market, raw materials, or a labour supply."}'::jsonb),
('business:4-5-business-location:match:640267c3', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Transport infrastructure”?", "options": ["A government-designated area offering incentives including reduced business rates, lower taxes on investment, and superfast broadband to attract businesses.", "An area where businesses can import goods without paying tariffs or VAT, unless those goods are sold in the wider UK market.", "A UK Government scheme to invest in infrastructure and provide funding for businesses across the north of England, from Liverpool to Hull.", "The roads, railways, airports and ports in an area for transporting goods and people, including ICT infrastructure like broadband."]}'::jsonb, '{"answer": 3, "explain": "“Transport infrastructure” means: The roads, railways, airports and ports in an area for transporting goods and people, including ICT infrastructure like broadband."}'::jsonb),
('business:4-5-business-location:match:6d5e252b', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Enterprise zone”?", "options": ["An area where businesses can import goods without paying tariffs or VAT, unless those goods are sold in the wider UK market.", "A UK Government scheme to invest in infrastructure and provide funding for businesses across the north of England, from Liverpool to Hull.", "A government-designated area offering incentives including reduced business rates, lower taxes on investment, and superfast broadband to attract businesses.", "An area near Cambridge with a high concentration of skilled ICT workers and technology firms."]}'::jsonb, '{"answer": 2, "explain": "“Enterprise zone” means: A government-designated area offering incentives including reduced business rates, lower taxes on investment, and superfast broadband to attract businesses."}'::jsonb),
('business:4-5-business-location:match:a7b19f9b', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Freeport”?", "options": ["An area where businesses can import goods without paying tariffs or VAT, unless those goods are sold in the wider UK market.", "A UK Government scheme to invest in infrastructure and provide funding for businesses across the north of England, from Liverpool to Hull.", "An area near Cambridge with a high concentration of skilled ICT workers and technology firms.", "Materials that are processed in some way as part of the manufacture of a product."]}'::jsonb, '{"answer": 0, "explain": "“Freeport” means: An area where businesses can import goods without paying tariffs or VAT, unless those goods are sold in the wider UK market."}'::jsonb),
('business:4-5-business-location:match:9d0a1952', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Northern Powerhouse”?", "options": ["An area near Cambridge with a high concentration of skilled ICT workers and technology firms.", "Materials that are processed in some way as part of the manufacture of a product.", "A UK Government scheme to invest in infrastructure and provide funding for businesses across the north of England, from Liverpool to Hull.", "The workers employed by a business to produce goods and services — a key factor of production."]}'::jsonb, '{"answer": 2, "explain": "“Northern Powerhouse” means: A UK Government scheme to invest in infrastructure and provide funding for businesses across the north of England, from Liverpool to Hull."}'::jsonb),
('business:4-5-business-location:match:55c120ab', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Silicon Fen”?", "options": ["Materials that are processed in some way as part of the manufacture of a product.", "The workers employed by a business to produce goods and services — a key factor of production.", "The total greenhouse gases produced by a business''s activities — reduced by shorter supply chains and local sourcing.", "An area near Cambridge with a high concentration of skilled ICT workers and technology firms."]}'::jsonb, '{"answer": 3, "explain": "“Silicon Fen” means: An area near Cambridge with a high concentration of skilled ICT workers and technology firms."}'::jsonb),
('business:4-5-business-location:match:5cedb1d5', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Raw materials”?", "options": ["The workers employed by a business to produce goods and services — a key factor of production.", "Materials that are processed in some way as part of the manufacture of a product.", "The total greenhouse gases produced by a business''s activities — reduced by shorter supply chains and local sourcing.", "Locating a business close to its customers to increase sales, improve communication, and reduce delivery costs."]}'::jsonb, '{"answer": 1, "explain": "“Raw materials” means: Materials that are processed in some way as part of the manufacture of a product."}'::jsonb),
('business:4-5-business-location:match:7ddca6a2', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Labour”?", "options": ["The total greenhouse gases produced by a business''s activities — reduced by shorter supply chains and local sourcing.", "Locating a business close to its customers to increase sales, improve communication, and reduce delivery costs.", "The workers employed by a business to produce goods and services — a key factor of production.", "Locating near the source of inputs used in production — most important when materials are bulky, perishable, or expensive to transport."]}'::jsonb, '{"answer": 2, "explain": "“Labour” means: The workers employed by a business to produce goods and services — a key factor of production."}'::jsonb),
('business:4-5-business-location:match:6d02ae58', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Carbon footprint”?", "options": ["Locating a business close to its customers to increase sales, improve communication, and reduce delivery costs.", "Locating near the source of inputs used in production — most important when materials are bulky, perishable, or expensive to transport.", "The place where a business is sited.", "The total greenhouse gases produced by a business''s activities — reduced by shorter supply chains and local sourcing."]}'::jsonb, '{"answer": 3, "explain": "“Carbon footprint” means: The total greenhouse gases produced by a business''s activities — reduced by shorter supply chains and local sourcing."}'::jsonb),
('business:4-5-business-location:match:18488f3f', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Proximity to market”?", "options": ["Locating near the source of inputs used in production — most important when materials are bulky, perishable, or expensive to transport.", "Locating a business close to its customers to increase sales, improve communication, and reduce delivery costs.", "The place where a business is sited.", "Nearness to something — such as a market, raw materials, or a labour supply."]}'::jsonb, '{"answer": 1, "explain": "“Proximity to market” means: Locating a business close to its customers to increase sales, improve communication, and reduce delivery costs."}'::jsonb),
('business:4-5-business-location:match:6ac2f6e2', 'business', 'business:4-5-business-location', '4.5 Business Location', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Proximity to raw materials”?", "options": ["The place where a business is sited.", "Locating near the source of inputs used in production — most important when materials are bulky, perishable, or expensive to transport.", "Nearness to something — such as a market, raw materials, or a labour supply.", "The roads, railways, airports and ports in an area for transporting goods and people, including ICT infrastructure like broadband."]}'::jsonb, '{"answer": 1, "explain": "“Proximity to raw materials” means: Locating near the source of inputs used in production — most important when materials are bulky, perishable, or expensive to transport."}'::jsonb),
('business:4-6-working-with-suppliers:exam:42a322e2', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'exam', 'mcq', 1, '{"num": "Q7", "question": "The role of procurement for a car manufacturer might involve:", "options": ["Advertising a new range of electric vehicles", "Negotiating deals with car showrooms", "Receiving deliveries of tyres and windscreens", "Testing the brakes of every new car"], "hint": "Think: which option is about BUYING or receiving goods — not selling, marketing, or testing?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Receiving deliveries of tyres and windscreens</h5><ul><li><strong>Why C is correct:</strong> Procurement covers all stages of buying — including receiving deliveries of components like tyres and windscreens (Stage 4 of procurement).</li><li><strong>Why A is wrong:</strong> Advertising is a marketing activity, not procurement.</li><li><strong>Why B is wrong:</strong> Negotiating with showrooms is a sales/distribution decision, not procurement.</li><li><strong>Why D is wrong:</strong> Testing brakes is a quality control or operations task, not procurement.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-6-working-with-suppliers:exam:5d42d53c', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'exam', 'mcq', 1, '{"num": "Q10", "question": "Hugh works in procurement at a factory that makes jeans. Which of the following would NOT be part of Hugh''s job role?", "options": ["Choosing a supplier of zips and buttons", "Ordering printer paper and ink cartridges", "Receiving delivery of threads and fabrics", "Sewing the size label on to the waistband"], "hint": "Procurement is about BUYING goods and services. Which option is a manufacturing/production task, not a purchasing task?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Sewing the size label on to the waistband</h5><ul><li><strong>Why D is correct:</strong> Sewing labels is a production/manufacturing task carried out on the factory floor — it has nothing to do with purchasing or procurement.</li><li><strong>Why A is wrong:</strong> Choosing a supplier of zips and buttons is Stage 2 of procurement — this is clearly part of Hugh''s role.</li><li><strong>Why B is wrong:</strong> Procurement covers ALL goods the business needs, including office supplies like printer paper — not just production materials.</li><li><strong>Why C is wrong:</strong> Receiving deliveries of threads and fabrics is Stage 4 of procurement.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-6-working-with-suppliers:exam:256c29f0', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'exam', 'mcq', 1, '{"num": "Q13", "question": "The length of a firm''s supply chain:", "options": ["Affects how quickly it can respond to changes in demand", "Depends on the production method used by the business", "Has no impact on the procurement function", "Is shown on an organisation chart"], "hint": "Think about Zara — how does its short, fast supply chain allow it to respond to fashion trends every two weeks?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A — Affects how quickly it can respond to changes in demand</h5><ul><li><strong>Why A is correct:</strong> A shorter supply chain allows a business to respond much more quickly to changes in customer demand — as shown by Zara''s 15-day turnaround. A longer chain means slower response times.</li><li><strong>Why B is wrong:</strong> Production methods (batch, flow, job) do not determine the length of the supply chain — these are separate decisions.</li><li><strong>Why C is wrong:</strong> Supply chain length absolutely affects procurement — longer chains are harder to manage and more prone to disruption.</li><li><strong>Why D is wrong:</strong> Organisation charts show internal staff hierarchy, not supply chain structure.</li></ul><p><strong>⚠️ Examiner''s Comment:</strong> This question is best approached by discounting wrong options one at a time. Many candidates rush MCQs — take time to eliminate each incorrect answer carefully.</p></div>", "modelAnswer": ""}'::jsonb),
('business:4-6-working-with-suppliers:exam:f2beba05', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'exam', 'mcq', 1, '{"num": "Q14", "question": "David works in a biscuit factory and is responsible for procurement. Which task is NOT likely to be part of David''s job role?", "options": ["Buying sugar", "Ordering biscuit packaging materials", "Purchasing stationery", "Selling biscuits"], "hint": "Procurement is about BUYING goods and services. Which option is about SELLING — which is a completely different business function?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Selling biscuits</h5><ul><li><strong>Why D is correct:</strong> Selling biscuits is a sales and marketing task — completely separate from procurement. Procurement manages purchasing/buying, not selling.</li><li><strong>Why A is wrong:</strong> Buying sugar is a core procurement task — purchasing raw materials for production.</li><li><strong>Why B is wrong:</strong> Ordering packaging materials is procurement — everything needed to operate the factory falls under procurement.</li><li><strong>Why C is wrong:</strong> Procurement covers all goods a business needs, including office stationery — not just production inputs.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-6-working-with-suppliers:exam:4ca48d03', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'exam', 'mcq', 1, '{"num": "Q15", "question": "Choosing how products will be delivered to customers is an example of a:", "options": ["Flow production issue", "Liquidity problem", "Logistical decision", "Purchasing concern"], "hint": "Logistics is the management of transportation and storage. Which answer word directly links to this?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Logistical decision</h5><ul><li><strong>Why C is correct:</strong> Choosing how products are delivered is a transportation/logistics decision — logistics manages the movement of goods from seller to buyer.</li><li><strong>Why A is wrong:</strong> Flow production is a manufacturing method (mass production on a conveyor belt) — it is not about delivery to customers.</li><li><strong>Why B is wrong:</strong> Liquidity is a finance concept about a business''s ability to meet short-term debts — nothing to do with delivery.</li><li><strong>Why D is wrong:</strong> Purchasing concerns involve buying goods and services — not deciding how finished products reach customers.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:4-6-working-with-suppliers:exam:5fef434d', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'exam', 'mcq', 1, '{"num": "Q17", "question": "Choosing which supplier to use is a:", "options": ["Marketing decision", "Pricing decision", "Procurement decision", "Sales decision"], "hint": "Which business function is specifically responsible for managing the buying and purchasing of goods and services?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Procurement decision</h5><ul><li><strong>Why C is correct:</strong> Selecting and managing suppliers is the core activity of procurement. Stage 2 of the procurement process is ''Choosing Suppliers''.</li><li><strong>Why A is wrong:</strong> Marketing involves promoting products and understanding customer needs — not purchasing from suppliers.</li><li><strong>Why B is wrong:</strong> Pricing decisions involve setting the price of the business''s own products or services.</li><li><strong>Why D is wrong:</strong> Sales decisions involve selling the business''s products to customers.</li></ul><p><strong>⚠️ Examiner''s Comment:</strong> Many candidates did not know what ''procurement'' meant, making all options seem plausible. Know your key terms — procurement is the management of purchasing within a business.</p></div>", "modelAnswer": ""}'::jsonb),
('business:4-6-working-with-suppliers:exam:4b9d8ae7', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'exam', 'mcq', 1, '{"num": "Q18", "question": "A supermarket decides to extend its opening hours. The supermarket is likely to need:", "options": ["A longer supply chain", "Fewer staff", "Lower quality products", "Reliable suppliers"], "hint": "Extended hours means more time when customers can buy products. What does the supermarket need to ensure those products are always available?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer: D — Reliable suppliers</h5><ul><li><strong>Why D is correct:</strong> Extended opening hours means goods must be available for longer periods. Reliable suppliers ensure shelves stay stocked throughout extended trading hours. Without reliable deliveries, extended hours would mean empty shelves.</li><li><strong>Why A is wrong:</strong> A longer supply chain increases risk and complexity — it makes stocking shelves harder, not easier.</li><li><strong>Why B is wrong:</strong> Extended hours typically require MORE staff to cover longer shifts, not fewer.</li><li><strong>Why C is wrong:</strong> There is no reason extended opening hours would reduce the quality required of products.</li></ul><p><strong>⚠️ Examiner''s Comment:</strong> This question is best approached by discounting wrong options. Each option is close to a right-sounding answer — careful elimination of A, B, and C reveals D as the only logical choice.</p></div>", "modelAnswer": ""}'::jsonb),
('business:4-6-working-with-suppliers:exam:3bb139ff', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'exam', 'mcq', 1, '{"num": "Q19", "question": "The data shows that:", "options": ["The company prefers to transport its goods by air", "The company''s transport costs have fallen year on year", "GLU plc spent more than £1.25 million on transport costs in 2018", "GLU plc transports more goods by rail than by road"], "caseStudy": "The transport costs of Global Logistics United plc (GLU plc) for the last five years are shown below.<br><br><table class=\"case-table\"><caption>Table 1 — GLU plc Transport Costs by Mode (2014–2018)</caption><tr><th>Mode of Transport</th><th>By Road</th><th>By Rail</th><th>By Air</th></tr><tr><td>2014</td><td>£150,000</td><td>£350,000</td><td>£600,000</td></tr><tr><td>2015</td><td>£160,000</td><td>£370,000</td><td>£620,000</td></tr><tr><td>2016</td><td>£170,000</td><td>£390,000</td><td>£635,000</td></tr><tr><td>2017</td><td>£180,000</td><td>£410,000</td><td>£640,000</td></tr><tr><td>2018</td><td>£190,000</td><td>£430,000</td><td>£650,000</td></tr></table>", "hint": "Add up all three transport costs for 2018: Road + Rail + Air. Is the total more than £1,250,000? Check each other option by working through the data carefully.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — GLU plc spent more than £1.25 million on transport costs in 2018</h5><ul><li><strong>Why C is correct:</strong> 2018 costs: Road £190,000 + Rail £430,000 + Air £650,000 = £1,270,000. This is greater than £1,250,000 ✅</li><li><strong>Why A is wrong:</strong> Higher air costs reflect the higher unit price of air freight, not a preference. We cannot determine preference from cost data alone.</li><li><strong>Why B is wrong:</strong> ALL costs increased year on year in every category — they did not fall.</li><li><strong>Why D is wrong:</strong> Higher rail costs than road costs do not mean more goods are transported by rail — air freight costs more per unit so fewer goods could generate a higher total cost.</li></ul><p><strong>⚠️ Examiner''s Comment:</strong> This numerical question required time to validate or discount each option. Do not rush MCQs — spend time checking the data carefully.</p></div>", "modelAnswer": ""}'::jsonb),
('business:4-6-working-with-suppliers:mcq:e5091ab9', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'mcq', 'mcq', 1, '{"question": "What is the correct definition of procurement?", "options": ["The process of transporting goods from seller to buyer", "The management of purchasing goods and services within a business", "The chain of businesses involved in producing and delivering a product", "The process of checking the quality of goods upon delivery"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Procurement is specifically the management of the purchasing/buying function within a business. Logistics (A) deals with transport and storage. The supply chain (C) is the wider chain of businesses. Quality checking (D) is part of operations, not procurement itself."}'::jsonb),
('business:4-6-working-with-suppliers:mcq:19078511', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'mcq', 'mcq', 1, '{"question": "Which of the following best describes logistics?", "options": ["Choosing which goods and services a business should sell", "Managing the quality of a finished product", "The management of the transportation and storage of goods", "The process of negotiating prices with suppliers"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Logistics is specifically about managing the movement and storage of goods. Choosing what to sell (A) is a marketing and procurement decision. Quality management (B) is a separate operations function. Negotiating prices (D) is part of procurement."}'::jsonb),
('business:4-6-working-with-suppliers:mcq:1f8224ab', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'mcq', 'mcq', 1, '{"question": "A longer supply chain means:", "options": ["A business will always receive lower quality goods", "It may be more difficult for a business to manage supplies", "It will take longer to find the right supplier", "The supplier will always demand higher prices"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. A longer supply chain involves more businesses, increasing complexity and the risk of disruption — making it harder to manage. It does NOT automatically mean lower quality (A), longer supplier searches (C), or higher prices (D)."}'::jsonb),
('business:4-6-working-with-suppliers:mcq:42a322e2', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'mcq', 'mcq', 1, '{"question": "The role of procurement for a car manufacturer might involve:", "options": ["Advertising a new range of electric vehicles", "Negotiating deals with car showrooms", "Receiving deliveries of tyres and windscreens", "Testing the brakes of every new car"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Receiving deliveries of components like tyres and windscreens is a classic procurement function (Stage 4 of procurement). Advertising (A) is marketing. Negotiating with showrooms (B) is sales. Brake testing (D) is quality control/operations."}'::jsonb),
('business:4-6-working-with-suppliers:mcq:4f9fba14', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'mcq', 'mcq', 1, '{"question": "Which of the following would NOT be part of a procurement officer''s job at a jeans factory?", "options": ["Choosing a supplier of zips and buttons", "Ordering printer paper and ink cartridges", "Receiving delivery of threads and fabrics", "Sewing the size label on to the waistband"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. Sewing labels is a production/manufacturing task, not a procurement task. Procurement covers choosing suppliers (A), ordering all goods the business needs including office supplies (B), and receiving deliveries (C)."}'::jsonb),
('business:4-6-working-with-suppliers:mcq:5fef434d', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'mcq', 'mcq', 1, '{"question": "Choosing which supplier to use is a:", "options": ["Marketing decision", "Pricing decision", "Procurement decision", "Sales decision"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Selecting and managing suppliers is the core function of procurement. It is not marketing (A), pricing (B), or sales (D). Many students confuse procurement with other business functions — procurement is specifically about the buying/purchasing side."}'::jsonb),
('business:4-6-working-with-suppliers:mcq:256c29f0', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'mcq', 'mcq', 1, '{"question": "The length of a firm''s supply chain:", "options": ["Affects how quickly it can respond to changes in demand", "Depends on the production method used by the business", "Has no impact on the procurement function", "Is shown on an organisation chart"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A. A shorter supply chain allows a business to respond more quickly to demand changes (like Zara''s 15-day turnaround). Production methods (B) do not determine supply chain length. The supply chain absolutely does impact procurement (C is wrong). Organisation charts show internal structure, not supply chains (D is wrong)."}'::jsonb),
('business:4-6-working-with-suppliers:mcq:4b9d8ae7', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'mcq', 'mcq', 1, '{"question": "A supermarket decides to extend its opening hours. The supermarket is likely to need:", "options": ["A longer supply chain", "Fewer staff", "Lower quality products", "Reliable suppliers"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. Extended opening hours means more products need to be on shelves for longer — this requires reliable suppliers to ensure stock does not run out. A longer supply chain (A) would make this harder, not easier. More staff would be needed (B is wrong). Product quality requirements do not decrease (C is wrong)."}'::jsonb),
('business:4-6-working-with-suppliers:mcq:4ca48d03', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'mcq', 'mcq', 1, '{"question": "Choosing how products will be delivered to customers is an example of a:", "options": ["Flow production issue", "Liquidity problem", "Logistical decision", "Purchasing concern"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Decisions about how to transport and deliver goods are logistical decisions — logistics is the management of transportation and storage. Flow production (A) is about manufacturing methods. Liquidity (B) is about cash in finance. Purchasing (D) is about buying inputs, not delivering outputs."}'::jsonb),
('business:4-6-working-with-suppliers:mcq:f2d5b0bc', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'mcq', 'mcq', 1, '{"question": "Which factor would be MOST important to a discount shop selling all goods at £1?", "options": ["Customer service from suppliers", "Length of the supply chain", "Cost of supplies", "Reliability of supply"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. A £1 discount shop has an extremely tight pricing model. It cannot absorb any increase in supply costs without losing its competitive advantage or profitability. Cost is therefore the dominant factor. While reliability (D) also matters to keep shelves stocked, the business model is fundamentally driven by keeping costs as low as possible."}'::jsonb),
('business:4-6-working-with-suppliers:mcq:97964ae6', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'mcq', 'mcq', 1, '{"question": "Crawford''s Biscuits factory was damaged in floods, halting production of custard creams. What type of supply chain problem does this illustrate?", "options": ["Poor customer service from Tesco", "A disruption in the reliability of supply", "A failure of Tesco''s logistics team", "A rise in variable costs at Tesco"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. The flood disrupted the reliable supply of custard creams — Crawford''s could not produce and therefore could not deliver. This is a supply reliability failure. It was not a customer service failure by Tesco (A), a logistics problem at Tesco (C), or directly a cost problem (D), though costs did rise later due to fuel prices."}'::jsonb),
('business:4-6-working-with-suppliers:mcq:46b2be13', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'mcq', 'mcq', 1, '{"question": "If JLR buys 500,000 tyres and 80% come from overseas suppliers, how many tyres come from overseas?", "options": ["80,000", "400,000", "420,000", "450,000"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. 500,000 × 80% = 500,000 × 0.8 = 400,000 tyres from overseas. Always show your working: (500,000 ÷ 100) × 80 = 400,000."}'::jsonb),
('business:4-6-working-with-suppliers:mcq:a991ed14', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'mcq', 'mcq', 1, '{"question": "The transport costs table for GLU plc (2014–2018) shows costs by road, rail, and air. Which statement about the data is correct?", "options": ["The company prefers to transport its goods by air", "The company''s transport costs have fallen year on year", "GLU plc spent more than £1.25 million on transport costs in 2018", "GLU plc transports more goods by rail than by road"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. In 2018: Road (£190,000) + Rail (£430,000) + Air (£650,000) = £1,270,000, which is more than £1.25 million. Option A is wrong — higher air costs reflect higher air prices, not preference. Option B is wrong — all costs increased year on year. Option D is wrong — we cannot determine volume from cost alone (air is most expensive per unit so higher cost ≠ more goods)."}'::jsonb),
('business:4-6-working-with-suppliers:tf:ad26bb18', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tf', 'tf', 1, '{"question": "Procurement is the management of the transportation and storage of goods."}'::jsonb, '{"answer": false, "explain": "FALSE. This is the definition of logistics, not procurement. Procurement is the management of purchasing within a business. This is one of the most common mix-ups students make in the exam."}'::jsonb),
('business:4-6-working-with-suppliers:tf:fc06e541', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tf', 'tf', 1, '{"question": "A longer supply chain is generally harder to manage than a shorter one."}'::jsonb, '{"answer": true, "explain": "TRUE. More businesses involved in the chain means more coordination, more points of potential failure, and greater complexity. A shorter supply chain is easier to manage and generally more reliable."}'::jsonb),
('business:4-6-working-with-suppliers:tf:04df850c', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tf', 'tf', 1, '{"question": "Just-in-time delivery means a business holds large stocks of materials in a warehouse at all times."}'::jsonb, '{"answer": false, "explain": "FALSE. Just-in-time is the opposite — materials and parts arrive exactly when needed for production, so the business holds minimal stock. This reduces storage costs but requires highly reliable suppliers."}'::jsonb),
('business:4-6-working-with-suppliers:tf:8dc523ec', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tf', 'tf', 1, '{"question": "Zara''s supply chain allows it to change clothing designs every two weeks."}'::jsonb, '{"answer": true, "explain": "TRUE. Zara''s highly responsive supply chain — buying fabric in bulk from European suppliers for fast delivery to its Spanish factory — allows it to get new designs to stores in just 15 days, enabling bi-weekly design changes."}'::jsonb),
('business:4-6-working-with-suppliers:tf:d226291d', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tf', 'tf', 1, '{"question": "The four stages of procurement are: identify goods, choose suppliers, order goods, receive deliveries."}'::jsonb, '{"answer": true, "explain": "TRUE. These are the four official stages of the procurement process in the correct order. You should be able to recall and explain all four in an exam."}'::jsonb),
('business:4-6-working-with-suppliers:tf:fa564f21', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tf', 'tf', 1, '{"question": "Choosing the cheapest supplier is always the best procurement decision for a business."}'::jsonb, '{"answer": false, "explain": "FALSE. The cheapest supplier may sacrifice quality, reliability, or ethical standards. A saving on costs could result in lower quality goods, less reliability, and a loss of reputation that is difficult to recover. Factors must be weighed together."}'::jsonb),
('business:4-6-working-with-suppliers:tf:d80e929f', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tf', 'tf', 1, '{"question": "If a supplier acts unethically, the reputation of the business that buys from them can also be damaged."}'::jsonb, '{"answer": true, "explain": "TRUE. The buying business is often blamed in the media even if it was unaware of the ethical problem. This is why businesses like Primark, Zara, and Costa Coffee invest heavily in auditing their supply chains."}'::jsonb),
('business:4-6-working-with-suppliers:tf:ece403e1', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tf', 'tf', 1, '{"question": "Tesco''s procurement department deals only with buying food products for its supermarkets."}'::jsonb, '{"answer": false, "explain": "FALSE. Procurement covers all goods and services a business needs to operate — including office supplies, cleaning services, technology, packaging, and more. It is not limited to the products sold in store."}'::jsonb),
('business:4-6-working-with-suppliers:tf:1a484b49', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tf', 'tf', 1, '{"question": "Reliability and time are closely linked logistical considerations."}'::jsonb, '{"answer": true, "explain": "TRUE. A supplier that is ''sometimes'' on time is not truly reliable. Reliability includes delivering the right goods, in the right quantity, at the right time — consistently. The two factors reinforce each other."}'::jsonb),
('business:4-6-working-with-suppliers:tf:6a60b89a', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tf', 'tf', 1, '{"question": "Eddie Stobart is an example of a procurement business."}'::jsonb, '{"answer": false, "explain": "FALSE. Eddie Stobart (now The Logistics Development Group) is a logistics business — it manages the transportation of goods. Procurement is the buying/purchasing function. Tesco is the one doing the procurement; Eddie Stobart handles the logistics."}'::jsonb),
('business:4-6-working-with-suppliers:tf:b980eea4', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tf', 'tf', 1, '{"question": "A business can lose customers if its logistics supplier is unreliable, even if the product itself is good."}'::jsonb, '{"answer": true, "explain": "TRUE. If goods are not delivered on time or are delivered incorrectly, the customer (who sees the retailer''s name, not the logistics firm''s) will lose confidence and may switch to a competitor. Poor logistics damages the reputation of the selling business."}'::jsonb),
('business:4-6-working-with-suppliers:learn:705545db', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>These are the essential terms you must be able to define accurately in the exam. Learn these using look, say, cover, write, check.</p>\n<ul>\n  <li><strong>Procurement:</strong> The management of purchasing (buying) goods and services within a business.</li>\n  <li><strong>Logistics:</strong> The management of the transportation and storage of goods from seller to buyer.</li>\n  <li><strong>Supply Chain:</strong> The chain of businesses involved in the production of a product and its delivery to the end user.</li>\n  <li><strong>Supplier:</strong> A party (business or individual) that supplies goods and/or services to another business.</li>\n  <li><strong>Just-In-Time (JIT):</strong> A system where parts or materials are delivered exactly when they are needed for production, minimising storage costs.</li>\n  <li><strong>Ethical Sourcing:</strong> Choosing suppliers who operate responsibly — paying fair wages, protecting workers, and using sustainable materials.</li>\n</ul>", "question": "Which statement correctly describes a Just-In-Time (JIT) system?", "options": ["Parts are delivered exactly when needed, keeping storage costs low", "Stock is reordered automatically once levels start running low", "Large buffer stocks are kept in the warehouse just in case", "Suppliers are chosen only because they charge the lowest price"]}'::jsonb, '{"answer": 0, "explain": "JIT means materials arrive exactly when needed on the production line, which cuts storage costs but relies on very reliable suppliers."}'::jsonb),
('business:4-6-working-with-suppliers:learn:17959802', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'learn', 'mcq', 1, '{"readingTitle": "The Procurement Process — 4 Stages", "reading": "<p><strong>Procurement</strong> is the management of all buying activity within a business. Whether it''s a supermarket buying thousands of product lines or a small café ordering coffee beans, every business must manage procurement. There are four key stages:</p>\n<ul>\n  <li><strong>Stage 1 — Identifying goods and services to buy:</strong> What to buy can be influenced by the time of year, changes in fashion, technology developments, or customer demand. For example, a clothing retailer must decide whether to stock winter coats or summer dresses based on the season.</li>\n  <li><strong>Stage 2 — Choosing suppliers:</strong> Who can supply the goods? What do they charge? What is their reputation for quality and reliability? Businesses must evaluate multiple suppliers before committing.</li>\n  <li><strong>Stage 3 — Ordering goods and services:</strong> The actual process of placing orders and procuring goods. Procurement teams consider whether bulk ordering offers a discount, or whether a longer contract reduces unit costs.</li>\n  <li><strong>Stage 4 — Receiving deliveries from suppliers:</strong> When will goods arrive? Where will they be stored? Access for delivery vehicles and sufficient storage space must be planned in advance.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Tesco plc</h4>\n  <p>Tesco is one of the UK''s largest retailers, selling thousands of product lines through its stores and online. Its procurement department manages relationships with hundreds of suppliers across the UK and abroad. If a supplier fails to deliver — say, during a factory flood like the Crawford''s Biscuits incident in 2016 — Tesco suffers immediately: empty shelves, lost sales, and damage to its reputation. This shows why all four stages of procurement must be managed carefully and continuously.</p>\n</div>", "question": "Deciding what to buy based on the time of year, fashion or technology belongs to which stage of procurement?", "options": ["Stage 1 – identifying what to buy", "Stage 2 – choosing suppliers", "Stage 3 – ordering the goods", "Stage 4 – receiving deliveries"]}'::jsonb, '{"answer": 0, "explain": "Identifying what to buy (influenced by season, fashion and technology) is Stage 1; choosing suppliers, ordering and receiving are the later stages."}'::jsonb),
('business:4-6-working-with-suppliers:learn:e1483bab', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'learn', 'mcq', 1, '{"readingTitle": "Factors Affecting What to Buy", "reading": "<p>Before a business can even choose a supplier, it must decide <em>what</em> to buy and <em>when</em> to buy it. Getting this wrong can lead to waste, lost sales, or surplus stock. Three key factors affect this decision:</p>\n<ul>\n  <li><strong>Time of year:</strong> Demand for many products is seasonal. A garden centre must stock barbeques and plants in spring/summer and pivot to Christmas items in winter. Ordering too early or too late leads to either stockouts or unsold goods sold at a loss.</li>\n  <li><strong>Changes in technology:</strong> Technology evolves rapidly. A business must avoid buying too much of a product that is about to be replaced by a newer model — for example, buying large quantities of a laptop that will be superseded in two months.</li>\n  <li><strong>Changes in fashion and lifestyle:</strong> Consumer tastes shift constantly. The rise of veganism and gluten-free diets has forced supermarkets to dramatically increase the range of plant-based and free-from products they procure. Failing to anticipate trends means missing sales opportunities.</li>\n</ul>", "question": "Why should a business consider changes in technology when deciding what to buy?", "options": ["To avoid overbuying stock soon to be replaced by a newer model", "Because newer technology is always cheaper to buy in bulk", "Because customers always prefer the oldest available models", "Because changing technology has no effect on demand at all"]}'::jsonb, '{"answer": 0, "explain": "Fast-changing technology risks a business being left with large stocks of a product about to be superseded, causing waste and lost value."}'::jsonb),
('business:4-6-working-with-suppliers:learn:51ea2a03', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'learn', 'mcq', 1, '{"readingTitle": "Choosing the Right Supplier", "reading": "<p>Choosing the wrong supplier can damage a business''s reputation, increase costs, and disrupt production. Businesses evaluate potential suppliers against several criteria:</p>\n<ul>\n  <li><strong>Quality of goods supplied:</strong> The quality of supplies must consistently meet the expected standard. Car manufacturers, for example, cannot afford faulty brake components — quality must be right every time.</li>\n  <li><strong>Reputation of the supplier:</strong> If a supplier is exposed for unethical practices (e.g., poor working conditions or child labour), the reputation of the buying business is also damaged — even if the buying business had no direct involvement. Primark and other fashion retailers have faced exactly this challenge.</li>\n  <li><strong>Cost of supplies:</strong> Lower costs can improve profit margins or allow the business to lower prices. However, the cheapest supplier is not always the best choice if it sacrifices quality or reliability.</li>\n  <li><strong>Reliability:</strong> Can the supplier deliver the right quantity of the right quality on time, every time? For fresh food retailers, daily reliability is non-negotiable.</li>\n  <li><strong>Customer service:</strong> When problems occur — late deliveries, faulty goods — how quickly and effectively will the supplier respond? Poor supplier customer service will force the buying business to find alternatives.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Zara (Fast Fashion)</h4>\n  <p>Zara is a global fashion retailer based in Spain with 2,270 stores worldwide. Its entire business model is built on speed — getting new designs from concept to shelf in just 15 days. To achieve this, Zara buys large quantities of fabric from European suppliers, which guarantees fast delivery to its factories in Spain. If its suppliers were unreliable, Zara could not change its clothing designs every two weeks (while competitors take two to three months). Reliable, quality suppliers are therefore central to Zara''s competitive advantage and its USP.</p>\n</div>", "question": "Why does a supplier''s reputation matter to the business that buys from it?", "options": ["A supplier''s unethical practices can damage the buyer''s reputation too", "A supplier''s reputation sets the tax rate the buying business pays", "A good reputation always means the supplier is the cheapest option", "A supplier''s reputation only ever affects the supplier, not the buyer"]}'::jsonb, '{"answer": 0, "explain": "Even if the buyer had no direct involvement, a supplier exposed for unethical practices damages the buyer''s reputation too."}'::jsonb),
('business:4-6-working-with-suppliers:learn:5adef4fd', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'learn', 'mcq', 1, '{"readingTitle": "Logistical Decisions — Time, Reliability, Supply Chain Length, Costs & Customer Service", "reading": "<p><strong>Logistics</strong> is the management of the transportation and storage of goods. Once a business has chosen its suppliers, it must ensure the physical movement of goods is managed effectively. Five key factors affect logistical decisions:</p>\n<ul>\n  <li><strong>Time:</strong> For some businesses, timing is critical. A plumber mid-job needs a part immediately. Car manufacturers use just-in-time delivery so parts arrive exactly when needed on the production line. Any delay stops production and costs money.</li>\n  <li><strong>Reliability of supply:</strong> A shop selling fresh bread needs daily deliveries — if a delivery fails, it has nothing to sell and its reputation suffers. Reliability and time work closely together: a supplier that is sometimes on time is not truly reliable.</li>\n  <li><strong>Length of the supply chain:</strong> The more businesses involved in getting a product from raw material to consumer, the higher the risk of disruption. A car maker relying on brake components from a specialist who relies on steel from a mine in another country has a very long and complex supply chain — one failure anywhere in that chain affects everyone downstream.</li>\n  <li><strong>Costs:</strong> Lower supply costs improve profit margins, but not at the expense of quality or reliability. Paying slightly more for a reliable, high-quality supplier often works out cheaper in the long run than constantly dealing with problems caused by a cheaper but unreliable one.</li>\n  <li><strong>Customer service from suppliers:</strong> Businesses are themselves customers of their suppliers. If a supplier fails to deliver or delivers faulty goods, how quickly do they resolve the problem? A supplier with poor customer service creates knock-on problems that damage the buying business''s own service to its customers.</li>\n</ul>", "question": "Why can paying slightly more for a reliable supplier work out cheaper overall?", "options": ["It avoids the repeated costs caused by an unreliable, cheaper supplier", "Reliable suppliers always charge less money than unreliable ones do", "A higher price always guarantees that goods will never be faulty", "Expensive suppliers always have much shorter supply chains overall"]}'::jsonb, '{"answer": 0, "explain": "A cheaper but unreliable supplier causes disruption and knock-on costs, so a dearer reliable one can be cheaper in the long run."}'::jsonb),
('business:4-6-working-with-suppliers:learn:df9a00b1', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'learn', 'mcq', 1, '{"readingTitle": "Advantages & Disadvantages of Long vs Short Supply Chains", "reading": "<p>One of the most important logistical decisions is how many businesses sit between raw material and final product. Here is how the length of the supply chain affects a business:</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Short Supply Chain</div>\n    <div class=\"pro-item\"><strong>Greater reliability:</strong> Fewer links in the chain means fewer points of potential failure. Disruption is less likely and easier to manage.</div>\n    <div class=\"pro-item\"><strong>Better communication:</strong> Fewer parties to coordinate with means faster responses to problems and clearer relationships.</div>\n    <div class=\"pro-item\"><strong>Lower transport costs:</strong> Shorter distances between supplier and business reduce delivery costs and carbon footprint.</div>\n    <div class=\"pro-item\"><strong>Faster delivery:</strong> Products arrive more quickly, which is vital for time-sensitive goods like fresh food or fashion.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Long Supply Chain</div>\n    <div class=\"con-item\"><strong>Higher risk of disruption:</strong> More businesses involved means more opportunities for something to go wrong — a strike, a flood, a factory fire — anywhere in the chain.</div>\n    <div class=\"con-item\"><strong>Harder to manage:</strong> Co-ordinating multiple businesses across different countries and time zones is complex and costly.</div>\n    <div class=\"con-item\"><strong>Quality control difficulties:</strong> Monitoring the quality and ethical standards of many suppliers across the world is extremely challenging.</div>\n    <div class=\"con-item\"><strong>Reputational risk:</strong> If one supplier in a long chain behaves unethically, the final seller bears much of the public criticism.</div>\n  </div>\n</div>", "question": "Which of these is an advantage of a short supply chain?", "options": ["Fewer links in the chain mean fewer points where failure can occur", "It spreads the reputational risk across many more businesses involved", "It allows the business to monitor many more suppliers worldwide", "It increases the number of countries the goods must travel through"]}'::jsonb, '{"answer": 0, "explain": "A shorter chain has fewer links to break, making it more reliable, easier to communicate along and cheaper to transport."}'::jsonb),
('business:4-6-working-with-suppliers:learn:0dde6988', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'learn', 'mcq', 1, '{"readingTitle": "Key Issues in Supply Chain Management", "reading": "<p>When things go wrong in a supply chain, the consequences ripple through the entire chain. The table below summarises the key issues and their potential problems:</p>\n<ul>\n  <li><strong>Time:</strong> If a supplier cannot deliver on time, production may halt and the business loses sales and revenue.</li>\n  <li><strong>Reliability:</strong> If the quantity or quality of goods supplied falls short, production is delayed or stopped, again leading to lost sales and revenue.</li>\n  <li><strong>Length of supply chain:</strong> A long supply chain increases the risk of problems at each stage — one broken link can halt the entire chain.</li>\n  <li><strong>Costs:</strong> High delivery costs raise total production costs. If costs become too high, the business may be unable to sell goods at a profit. Keeping delivery costs low is important, but not at the expense of reliability.</li>\n  <li><strong>Customer service:</strong> If a supplier has poor customer service, the buying business may lose its own customers due to unresolved problems and delays.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Crawford''s Biscuits & Tesco (2016)</h4>\n  <p>In 2016, Crawford''s Biscuits factory in Carlisle was badly damaged during winter floods, halting production of custard creams. Tesco could not get enough biscuits to meet customer demand. When production eventually restarted, rising UK fuel prices pushed up transport costs, threatening Tesco''s ability to keep prices competitive. This real-world example shows how natural disasters, supply chain disruptions, and rising costs can combine to damage a retailer''s sales and profitability — even when the problem originates with a supplier, not the retailer itself.</p>\n</div>", "question": "What is the likely consequence for a business if a supplier repeatedly fails to deliver on time?", "options": ["Production may halt, leading to lost sales and revenue", "The business''s supply chain automatically becomes shorter", "The supplier''s customer service costs fall", "The business gains an advantage over rivals"]}'::jsonb, '{"answer": 0, "explain": "Late supply can halt production, so the business loses sales and revenue even though the fault lies with the supplier."}'::jsonb),
('business:4-6-working-with-suppliers:learn:2f0983e7', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'learn', 'mcq', 1, '{"readingTitle": "Ethical Sourcing & Sustainable Supply Chains", "reading": "<p>Increasingly, businesses must think beyond price and reliability when choosing suppliers. Consumers, investors, and regulators are all paying close attention to <strong>ethical sourcing</strong> — how and where a business''s supplies are produced.</p>\n<ul>\n  <li><strong>Living wages:</strong> Businesses like Primark have committed to encouraging their supply chains to pay workers a living wage. Ethical treatment of workers reduces the risk of negative press coverage and boycotts.</li>\n  <li><strong>Sustainable materials:</strong> Primark sources material from sustainable sources to give clothes a longer life and reduce environmental impact. This appeals to environmentally-conscious consumers and reduces long-term resource risk.</li>\n  <li><strong>Certified suppliers:</strong> Costa Coffee uses Rainforest Alliance-certified suppliers, guaranteeing ethical and environmental standards. This protects Costa''s reputation and aligns with its brand values.</li>\n  <li><strong>Reputational risk:</strong> Unethical suppliers damage the reputation of the businesses that buy from them. Even if a retailer was unaware of the problem, they often face the most public criticism.</li>\n</ul>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Benefits of Ethical Sourcing</div>\n    <div class=\"pro-item\"><strong>Reputation:</strong> Enhances brand image and builds customer loyalty, especially among younger, ethically-conscious consumers.</div>\n    <div class=\"pro-item\"><strong>Legal compliance:</strong> Reduces the risk of breaching supply chain regulations and consumer protection laws.</div>\n    <div class=\"pro-item\"><strong>Long-term sustainability:</strong> Sustainable sourcing protects the supply of raw materials into the future.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Drawbacks of Ethical Sourcing</div>\n    <div class=\"con-item\"><strong>Higher costs:</strong> Ethically sourced materials and certified suppliers often charge more, increasing variable costs.</div>\n    <div class=\"con-item\"><strong>Fewer options:</strong> Limiting suppliers to those with ethical certification reduces choice and negotiating power.</div>\n    <div class=\"con-item\"><strong>Monitoring difficulty:</strong> Verifying ethical standards throughout a global supply chain is complex and expensive.</div>\n  </div>\n</div>", "question": "Which of the following is a drawback of ethical sourcing for a business?", "options": ["Certified, ethically sourced materials often cost more to buy", "It always reduces brand loyalty among younger, ethical consumers", "It removes any need to monitor the global supply chain at all", "It guarantees that the business breaks consumer protection law"]}'::jsonb, '{"answer": 0, "explain": "Ethical and certified suppliers tend to cost more and offer fewer options, and standards are hard to monitor across a global chain."}'::jsonb),
('business:4-6-working-with-suppliers:misc:df91101f', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Procurement and logistics mean the same thing.</p><p><strong>✅ The correct idea:</strong> They are two distinct concepts. Procurement is about managing the buying/purchasing of goods. Logistics is about managing the transportation and storage of goods. Many students swap these definitions and lose marks.</p>", "question": "Which statement correctly distinguishes procurement from logistics?", "options": ["Procurement handles buying goods; logistics handles transport", "Procurement handles transporting goods; logistics handles the buying", "Both terms simply describe managing the storage space for goods", "Both terms simply mean choosing which products a shop will sell"]}'::jsonb, '{"answer": 0, "explain": "Procurement is the buying/purchasing function; logistics is the transport and storage of goods — swapping them loses marks."}'::jsonb),
('business:4-6-working-with-suppliers:misc:1079f6d6', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The supply chain only includes the final manufacturer and the customer.</p><p><strong>✅ The correct idea:</strong> The supply chain includes ALL businesses involved from raw material to the end user. A car''s supply chain might include mines, steel producers, component manufacturers, the car assembler, and the dealer — all are part of the chain.</p>", "question": "Which businesses does a product''s supply chain include?", "options": ["All businesses involved from the raw material stage to the end user", "Only the final manufacturer and the customer who buys the product", "Only the shop that sells the product and the customer who buys it", "Only businesses based within the same country as the retailer"]}'::jsonb, '{"answer": 0, "explain": "The supply chain covers every business from raw material to end user — for a car that includes mines, steel producers, component makers, assembler and dealer."}'::jsonb),
('business:4-6-working-with-suppliers:misc:08fea7e2', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A longer supply chain means lower costs because more suppliers are competing.</p><p><strong>✅ The correct idea:</strong> A longer supply chain actually tends to increase costs and risk. More businesses means more transport, more handling, more coordination, and more potential points of failure. Costs are generally higher and reliability is lower in a long supply chain.</p>", "question": "What is the general effect of a longer supply chain on costs and risk?", "options": ["It tends to increase both overall costs and the risk of disruption", "It lowers costs because so many more suppliers are competing", "It lowers risk because responsibility is shared between more firms", "It has no real effect on either costs or the risk involved"]}'::jsonb, '{"answer": 0, "explain": "More businesses in the chain means more transport, handling and coordination, so costs and the risk of disruption both tend to rise."}'::jsonb),
('business:4-6-working-with-suppliers:misc:7d66e029', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Low-cost suppliers will allow a business to raise its prices and make more profit.</p><p><strong>✅ The correct idea:</strong> Low-cost suppliers allow a business to either keep prices competitive (lower than rivals) OR increase profit margins by keeping selling prices the same while paying less for inputs. They do not justify price increases — Primark, for example, uses low-cost suppliers specifically to undercut rivals on price.</p>", "question": "What does using low-cost suppliers actually allow a business to do?", "options": ["Keep prices lower than rivals or raise its profit margins", "Justify raising its selling prices well above those of rivals", "Automatically improve the quality of every product it sells", "Ignore how reliable its suppliers are when placing orders"]}'::jsonb, '{"answer": 0, "explain": "Lower input costs let a business undercut rivals on price or widen its margins — they do not justify raising prices."}'::jsonb),
('business:4-6-working-with-suppliers:misc:af2d45dc', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Procurement only covers the goods a business sells to customers.</p><p><strong>✅ The correct idea:</strong> Procurement covers ALL goods and services a business needs to operate — including office stationery, cleaning services, IT equipment, and staff uniforms — as well as stock. David the biscuit factory procurement officer orders sugar AND printer paper.</p>", "question": "What does the procurement function actually cover?", "options": ["Everything the business needs to run, including stock and supplies", "Only the finished products the business sells to its customers", "Only the transportation of the business''s finished goods", "Only office supplies such as stationery and printer paper"]}'::jsonb, '{"answer": 0, "explain": "Procurement covers all goods and services a business needs — stock plus stationery, cleaning, IT and uniforms — not just what it sells."}'::jsonb),
('business:4-6-working-with-suppliers:misc:64c05cf0', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If a business has a reliable supplier, cost is irrelevant.</p><p><strong>✅ The correct idea:</strong> Both reliability AND cost must be considered together. A very reliable but extremely expensive supplier may make the business unprofitable. The examiner expects students to evaluate both factors, not treat one as automatically more important.</p>", "question": "Once a business has found a reliable supplier, how important is cost?", "options": ["Cost still matters — a very reliable supplier can still be too costly", "Cost becomes completely irrelevant once reliability is guaranteed", "Cost then becomes the only factor that really matters at all", "Cost only ever matters when a supplier proves to be unreliable"]}'::jsonb, '{"answer": 0, "explain": "The examiner expects both reliability and cost to be weighed together; a reliable but too-expensive supplier can still make the business unprofitable."}'::jsonb),
('business:4-6-working-with-suppliers:misc:e2b53d94', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Just-in-time means the business orders goods just before they run out.</p><p><strong>✅ The correct idea:</strong> Just-in-time (JIT) is a precise system where materials arrive exactly when needed on the production line — not simply ''ordering when stock is low''. It requires highly reliable suppliers and sophisticated coordination between buyer and supplier.</p>", "question": "What does Just-In-Time (JIT) precisely involve?", "options": ["Materials arrive exactly when needed by reliable suppliers", "Ordering goods just before the existing stock finally runs out", "Holding large safety stocks just in case deliveries are delayed", "Buying materials only from whichever supplier is cheapest"]}'::jsonb, '{"answer": 0, "explain": "JIT is a precise system where materials arrive exactly when needed on the line — not simply reordering when stock is low."}'::jsonb),
('business:4-6-working-with-suppliers:misc:7388003d', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A business that uses ethical suppliers will always have higher costs.</p><p><strong>✅ The correct idea:</strong> While ethical suppliers can be more expensive, this is not always the case. Ethical sourcing can also bring long-term savings through reduced reputational risk, better supplier relationships, and more sustainable supply of materials. The examiner expects a balanced answer.</p>", "question": "Is it true that using ethical suppliers always means higher costs?", "options": ["No — it can bring long-term savings via lower reputational risk", "Yes — ethical suppliers are always the most expensive option", "Yes — because ethical suppliers never offer discounts", "No — ethical sourcing has no effect on costs at all"]}'::jsonb, '{"answer": 0, "explain": "Ethical suppliers can cost more, but the examiner expects a balanced answer: they can also save money through lower reputational risk and better relationships."}'::jsonb),
('business:4-6-working-with-suppliers:tips:a2a4cabc', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1 mark — One Fact. Nothing More. Move On.", "reading": "\n      <p>A 1-mark <strong>''State'' or ''Identify''</strong> question needs exactly one correct, specific point. No explanation. No examples. No full sentences required.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>One clear, specific point = 1 mark ✅</li>\n        <li>A vague, general answer = 0 marks ❌</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"Procurement is about suppliers.\"</em><br/>\n      This is too vague — it says nothing specific about what procurement does.</p>\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"Choosing suppliers.\"</em> or <em>\"Ordering goods and services.\"</em><br/>\n      Short, specific, and directly answers the question.</p>\n      <p><strong>⚠️ Examiner Warning:</strong> The examiner''s report noted that more than half of candidates did not know what the ''procurement function'' meant — many linked it to finance or marketing. Know your key terms cold.</p>\n    ", "question": "What does a 1-mark ''State'' or ''Identify'' question require?", "options": ["One clear, specific point with no explanation needed", "A point plus a full explanation of why it matters", "A judgement supported by case study context", "Two connected points linked to the business"]}'::jsonb, '{"answer": 0, "explain": "A 1-mark State/Identify answer needs exactly one specific point — a vague answer scores zero and no explanation is required."}'::jsonb),
('business:4-6-working-with-suppliers:tips:4033aa97', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Point + Link = 2 Marks", "reading": "\n      <p>A 2-mark <strong>''Explain''</strong> question requires two connected steps: a point of knowledge AND a brief explanation of how it works or why it matters.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 (K):</strong> State the relevant fact or concept.</li>\n        <li><strong>Step 2 (APP):</strong> Link it briefly to the business in the question.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark max):</strong><br/>\n      <em>\"JLP''s procurement team orders goods.\"</em><br/>\n      This states a role but gives no application to JLP specifically.</p>\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"One role of procurement is choosing which suppliers to use (K) — for example, JLP takes time evaluating high quality suppliers for its wide range of products including clothing and electronics (APP).\"</em></p>\n    ", "question": "What two steps earn full marks on a 2-mark ''Explain'' question?", "options": ["State a relevant point, then briefly link to the business", "State two separate points but never apply either one", "Give a judgement, then justify that judgement fully enough", "Write a full four-paragraph evaluation of the topic"]}'::jsonb, '{"answer": 0, "explain": "Point + Link: state the knowledge (K) then apply it to the business in the question (APP) — a point with no application caps you at one mark."}'::jsonb),
('business:4-6-working-with-suppliers:tips:5eee72f8', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "\n      <p>Every 3-mark Analyse question on this topic follows the same structure. Miss any one of the three steps and you miss a mark. Miss application and you <strong>cannot</strong> gain the analysis mark either.</p>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State the benefit/impact/concept clearly. e.g., \"Having low-cost suppliers helps a business keep its prices lower than rivals...\"</li>\n        <li><strong>Step 2 — Application (APP):</strong> Quote or reference the specific business from the case study. e.g., \"...As Primark aims to sell clothing and homeware at prices lower than most other retailers...\"</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> State the business-facing financial or operational impact. e.g., \"...this will help Primark increase its market share and maintain its competitive advantage.\"</li>\n      </ul>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write everything you know about procurement or supply chains. Examiners only award marks for content that directly answers the specific question asked.</p>\n      <p><strong>💡 The \"So What?\" Rule:</strong> After each sentence, ask yourself \"So what?\" until you reach a bottom-line business impact (profit, sales, reputation, market share, costs).</p>\n      <p><em>\"Low-cost suppliers keep costs down.\" → So what? → \"This improves profit margins.\" → So what? → \"This allows Primark to survive and grow in a competitive retail market.\"</em> ✅</p>\n    ", "question": "In a 3-mark Analyse answer, what happens if you leave out application?", "options": ["You cannot gain the analysis mark either", "You still earn full marks if the analysis is strong", "You lose only the application mark", "You gain an extra mark for a conclusion"]}'::jsonb, '{"answer": 0, "explain": "The chain is U → APP → AN; without application you forfeit the analysis mark too, so the case study must be used."}'::jsonb),
('business:4-6-working-with-suppliers:tips:8de8459d', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tips', 'mcq', 1, '{"readingTitle": "Analyse Two Impacts — 6 marks — Two Separate 3-Mark Answers", "reading": "\n      <p>A 6-mark question is simply <strong>two 3-mark questions written back-to-back</strong>. Each impact needs its own U → APP → AN chain.</p>\n      <p><strong>The Structure:</strong></p>\n      <ul>\n        <li><strong>Impact 1:</strong> U → APP → AN (3 marks)</li>\n        <li><strong>Impact 2:</strong> U → APP → AN (3 marks)</li>\n      </ul>\n      <p><strong>⚠️ Warning:</strong> Do NOT write a conclusion. There are zero marks available for evaluation in a 6-mark question. Spend the time making sure both impacts are fully analysed with application instead.</p>\n      <p><strong>Example (Pukka Pies, 6 marks):</strong></p>\n      <p><em>Impact 1 — Supply Chain Length: \"A long supply chain involves many businesses (U). Pukka Pies sources ingredients from across the UK and overseas (APP). This makes it harder to coordinate deliveries, increasing the risk that ingredients do not arrive on time and production is disrupted (AN).\"</em></p>\n      <p><em>Impact 2 — Time-Critical Logistics: \"Timing is vital for delivering fresh ingredients to ensure production is not delayed (U). Pukka Pies makes high-quality savoury pies that need fresh ingredients and has food safety as a key value (APP). If deliveries are late, the business may need to recall products or halt production, increasing costs and damaging its reputation (AN).\"</em></p>\n    ", "question": "Should you write a conclusion in a 6-mark ''Analyse two impacts'' question?", "options": ["No — there are no evaluation marks, so focus fully on both impacts", "Yes — a strong conclusion earns the final two marks available", "Yes — the conclusion is where application marks are always awarded", "No — a 6-mark question actually only needs one full impact"]}'::jsonb, '{"answer": 0, "explain": "A 6-mark question is two 3-mark U→APP→AN chains with no evaluation marks, so a conclusion wastes time better spent analysing."}'::jsonb),
('business:4-6-working-with-suppliers:tips:2244fad8', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 7 marks — Argue Both Sides, Then Make a Justified Judgement", "reading": "\n      <p>A 7-mark evaluate question tests all skills. You need application, analysis, AND a justified evaluation. This is the question where most students leave marks on the table.</p>\n      <p><strong>The 4-Paragraph Structure:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — K &amp; U:</strong> Introduce the key concept and show you understand the issue. e.g., \"Reliable suppliers are those who consistently deliver the right quality and quantity on time...\"</li>\n        <li><strong>Paragraph 2 — AN &amp; APP (Side A):</strong> Analyse the first side using case study context. e.g., \"Given that Zara has 2,270 stores (APP), reliable suppliers ensure products are available in every shop — without them, Zara would miss out on sales (AN).\"</li>\n        <li><strong>Paragraph 3 — AN &amp; APP (Counter-argument):</strong> Analyse the other side. e.g., \"However, if customer incomes fall, Zara''s sales will decline regardless of supplier reliability (APP/AN).\"</li>\n        <li><strong>Paragraph 4 — Evaluation (3 points):</strong> Make a justified decision using context. Decision + Reason using context + Qualifying condition (\"It depends on...\").</li>\n      </ul>\n      <p><strong>✅ Evaluation Sentence Starters:</strong></p>\n      <ul>\n        <li>\"Overall, I believe reliable suppliers are the most important factor for Zara because...\"</li>\n        <li>\"Without reliable suppliers, Zara''s USP of changing designs every 2 weeks would be impossible...\"</li>\n        <li>\"However, this depends on whether Zara''s competitors also improve their supply chains...\"</li>\n      </ul>\n      <p><strong>❌ A weak conclusion that scores 0 eval marks:</strong><br/>\n      <em>\"In conclusion, reliable suppliers are important for Zara.\"</em><br/>\n      This just repeats what was already said. A good evaluation adds NEW reasoning, a condition, or a comparison.</p>\n    ", "question": "What makes a conclusion score evaluation marks in a 7-mark question?", "options": ["It adds new reasoning, a condition, or a comparison", "It restates the strongest point already made before", "It lists every fact known about the topic", "It avoids mentioning the case study business"]}'::jsonb, '{"answer": 0, "explain": "Evaluation marks reward a justified judgement that adds something new — a condition (''it depends on...'') or comparison — not a repeat of earlier points."}'::jsonb),
('business:4-6-working-with-suppliers:tips:95774d94', 'business', 'business:4-6-working-with-suppliers', '4.6 Working with Suppliers', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate (Recommend) — 3 marks — Judgement + Justification + Context", "reading": "\n      <p>Some 3-mark questions ask you to <strong>recommend</strong> or <strong>evaluate</strong> between two options. This is a mini-evaluation requiring three clear elements.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Judgement (1 mark):</strong> State your clear choice. e.g., \"I think reliability is the most important consideration for Tesco when choosing a logistics business.\"</li>\n        <li><strong>Justification (1 mark):</strong> Give a reason that compares both options. e.g., \"If the logistics operator is not reliable, goods will not be on shelves at the right time and customers will go to competitors — having a greater impact than a small cost increase.\"</li>\n        <li><strong>Context (1 mark):</strong> Use specific detail from the case study to support your judgement.</li>\n      </ul>\n      <p><strong>⚠️ Critical Rule:</strong> Your justification MUST compare both options (cost vs reliability, meeting vs email, etc.). Simply saying why Option A is good, without comparing it to Option B, will not earn the full justification mark.</p>\n    ", "question": "What must the justification do in a 3-mark ''recommend'' question?", "options": ["Compare both options rather than just explain why one is good", "Simply repeat the judgement again but using different words", "Describe only the chosen option in a lot of detail", "Avoid using any specific detail from the case study"]}'::jsonb, '{"answer": 0, "explain": "A recommend answer needs judgement + justification + context, and the justification must compare both options to earn its mark."}'::jsonb),
